var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女と共にいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"앗, 사장님께서 먼저 이 모습으로 만나자고 하실 줄은 몰랐어요!","JPN":"あっ、社長か先にこの姿で会おうって言うなんて意外ですね！","ENG":"Oh! I didn't think you wanted to meet me in this form first, Boss.","TWN":"喔，沒想到老闆會先要我以這種姿態見面！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"왜냐하면 저는 인간으로, 남기로 정했으니까요.","JPN":"だって私、人間として残るって決めましたから。","ENG":"I chose to stay human, after all.","TWN":"因為我決定以人類的身份留下來。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"꼭 필요한 순간이 아니면, 다른 사람 앞에서는 이 모습을 드러내지 않기로 했거든요.","JPN":"仕方のない時じゃないと、他の人の前ではこの姿を見せちゃだめって思ったんです。","ENG":"I promised myself I wouldn't reveal this form to anyone unless it was truly necessary.","TWN":"除非是必要時刻，否則我不會在別人面前顯露出這副模樣。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"무, 물론…! 가끔 늦잠 자버렸을 때는 남몰래 날개를 꺼내기도 하지만요……!","JPN":"も、もちろん……！　たまに寝坊しちゃった時にはこっそり翼を出したりしますけど……！","ENG":"O-of course...! I do secretly use my wings when I oversleep sometimes...!","TWN":"當，當然！偶爾睡過頭的時候，也會偷偷地把翅膀拿出來用！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"앗, 이건 비밀이에요! 사장님과 저, 둘만의 비밀!","JPN":"あっ、これは内緒ですよ！　社長と私、2人だけの秘密！","ENG":"Ah, but that's a secret! Just between you and me, Boss!","TWN":"不過，這是秘密喔！這是我和老闆之間的秘密！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"음? 사장님한테도 비밀이 있다고요? 그게 뭔가요?","JPN":"うん？　社長にも秘密があるんですか？　それってなんですか？","ENG":"Hmm? You have a secret too, Boss? What is it?","TWN":"嗯？老闆也有秘密？那是什麼？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L19_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"오오옷!?","JPN":"おおおっ？！","ENG":"W-whoa?!","TWN":"喔喔喔？！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"이 영롱한 금빛 계약서가 바로 소문으로만 듣던 그 종신 계약서로군요……!","JPN":"この輝かしい金色の契約書が、あの噂の終身契約書なんですね……！","ENG":"This radiant golden contract... it must be the lifetime contract I've only heard about in rumors...!","TWN":"這份閃耀的金色契約就是傳說中的終身契約嗎！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L22_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"허걱…!? 그렇다는 말은, 설마……!?","JPN":"はっ……？！　ということは、まさか……？！","ENG":"H-hold on...! Does that mean...?!","TWN":"哎呀…？！這麼說，難道……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"사장님, 그럼 저와 종신 계약을 맺으시겠다는 말씀인가요!?","JPN":"社長、私と終身契約をするって言うんですか？！","ENG":"Boss, does this mean... you want to make a lifetime contract with me?!","TWN":"老闆，是說要和我簽訂終身契約嗎？！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"우오오오오오……!","JPN":"うおおおおお……！","ENG":"Whoooooa...!","TWN":"嗚噢噢噢噢噢……！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"만세! 해냈다! 이제 저도 어엿한 코핀 컴퍼니의 식구로군요!","JPN":"わーい！　やった！　これで私も立派なコフィンカンパニーの家族なんですね！","ENG":"Hooray! I did it! I'm officially part of the Coffin Company family now!","TWN":"萬歲！成功了！我現在也是科芬公司的一員了！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L27_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"가족 같은 회사 너무 좋아! 사장님, 사랑해요!","JPN":"家族のような会社、大好き！　社長、大好き！","ENG":"A company that feels like family? I'm all in! I love you, Boss!","TWN":"像家人一樣的公司，我超喜歡的！老闆，我愛你！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"엇!? 너무 기쁜 나머지 그만 사장님을 끌어안고 말았네요……!","JPN":"あっ？！　あまりにも嬉しくてつい社長とハグしてしまいました……！","ENG":"Ah! I got so excited, I hugged you before I knew it...!","TWN":"哎呀？！對不起！我一時太開心，不小心抱了老闆……！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"흑, 분명 기쁜데 어째서……","JPN":"うっ、あ、あれ？　変だな、嬉しいのに……","ENG":"*Sob* I'm really happy, so why...","TWN":"嗚，明明很開心，為什麼……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"흐윽!","JPN":"ううっ！","ENG":"*Sniffle!*","TWN":"呃呃！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L33_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"분명히 기쁜 날일 텐데, 어째서 눈물이 나는 걸까요……?","JPN":"本当に嬉しい日なのに、どうして涙が出るんでしょう……？","ENG":"This should be a happy day, so why am I crying...?","TWN":"明明是開心的日子，為什麼會流淚呢……？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"마음껏… 울어도 괜찮다고요……?","JPN":"思いきり……泣いても大丈夫なんですか……？","ENG":"It's really okay... for me to cry as much as I want...?","TWN":"盡情地……哭出來也沒關係嗎……？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"흑! 끄윽…!","JPN":"うっ！　ううっ……！","ENG":"*Sniffle…!*","TWN":"嗚！嗚嗚……！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"후에에에에에에에엥……!!","JPN":"ふわあああああああん……！！","ENG":"Waaaaah...!","TWN":"嗚嗚嗚嗚嗚……！！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"……에헤헤, 못난 꼴 보여버렸네요.","JPN":"……えへへ、だらしない姿を見せてしまいました。","ENG":"...Hehe, I must look so silly right now.","TWN":"……嘿嘿，讓老闆看到我這麼糗的樣子。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"감사해요, 사장님.","JPN":"ありがとうございます、社長。","ENG":"Thank you, Boss.","TWN":"謝謝你，老闆。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"이 회사에서 맺은 소중한 인연 덕분에 저는 이 세계에 남을 수 있었어요.","JPN":"この会社で出会った大切な絆のおかげで、私はこの世界に残ることができたんです。","ENG":"Because of the precious connections I've made in this company, I've been able to stay in this world.","TWN":"因為在這家公司結下的珍貴緣分，我才能留在這個世界。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"제가 인간으로 남을 수 있었던 건, 모두 사장님과 코핀 식구들의 노력 덕분이에요.","JPN":"私が人間として残れたのは、全部社長とコフィンのみんなが頑張ってくれたおかげです。","ENG":"I was only able to remain human thanks to you and everyone at Coffin Company.","TWN":"我能保持人類的身份，全靠老闆和科芬大家的努力。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"외톨이가 된 저에게, 있을 곳을 만들어 주셔서 감사해요.","JPN":"独りぼっちになった私に、居場所を作ってくれてありがとう。","ENG":"Thank you for giving someone like me, all alone, a place to belong.","TWN":"感謝你為我這個孤獨的人創造一個容身之所。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"좌절해 버린 저에게, 손을 뻗어 주셔서 감사해요.","JPN":"絶望してしまった私に、手を伸ばしてくれてありがとう。","ENG":"Thank you for reaching out to me when I had lost all hope.","TWN":"感謝你在我絕望時伸出援手。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L48_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"저, 언제까지나 잊지 않을게요.","JPN":"私、いつまでも忘れません。","ENG":"I'll never forget this. Not ever.","TWN":"我會永遠記得的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};